body.script:
const DATA_URL = 'deals.xml';

let allDeals = [];
let activeHours = 2;
let activeSort = 'date';
let activeLayout = 'tile';
let lastGeneratedIso = null;

const FAVORITES_KEY = 'slickdeals_favorites';

// favorites maps link -> full deal snapshot (title, thumbnail, rating, etc.)
// so a favorited deal still renders correctly even after it ages out of
// deals.xml and is no longer part of allDeals.
function loadFavorites() {
  try {
    const raw = JSON.parse(localStorage.getItem(FAVORITES_KEY) || 'null');
    const map = new Map();
    if (Array.isArray(raw)) {
      // Legacy format from an earlier version: just an array of links, no
      // snapshot data available yet. It'll self-heal once the deal is seen
      // again in allDeals (see getFavoriteDeals).
      raw.forEach(link => { if (typeof link === 'string') map.set(link, { link }); });
    } else if (raw && typeof raw === 'object') {
      Object.values(raw).forEach(deal => {
        if (deal && deal.link) map.set(deal.link, deal);
      });
    }
    return map;
  } catch {
    return new Map();
  }
}

let favorites = loadFavorites();

function saveFavorites() {
  const obj = {};
  favorites.forEach((deal, link) => { obj[link] = deal; });
  localStorage.setItem(FAVORITES_KEY, JSON.stringify(obj));
}

function escapeAttr(str) {
  return String(str).replace(/&/g, '&').replace(/"/g, '"').replace(/'/g, ''');
}

function toggleFavorite(link, isChecked) {
  if (isChecked) {
    const deal = allDeals.find(d => d.link === link);
    favorites.set(link, deal || { link });
  } else {
    favorites.delete(link);
  }
  saveFavorites();
  render();
}

function clearFavorites() {
  favorites.clear();
  saveFavorites();
  render();
}

// Returns { deal, archived } for every favorite: live data (kept fresh in
// storage) while the deal is still in the feed, or the last saved snapshot
// once it ages out and disappears from deals.xml.
function getFavoriteDeals() {
  const result = [];
  let changed = false;

  favorites.forEach((storedDeal, link) => {
    const live = allDeals.find(d => d.link === link);
    if (live) {
      if (JSON.stringify(live) !== JSON.stringify(storedDeal)) {
        favorites.set(link, live);
        changed = true;
      }
      result.push({ deal: live, archived: false });
    } else {
      result.push({ deal: storedDeal, archived: true });
    }
  });

  if (changed) saveFavorites();
  return result;
}

async function loadDeals() {
  // Cache-bust both the browser cache and any CDN/proxy cache (e.g. GitHub
  // Pages) by putting a unique query string on every request.
  const bustUrl = `${DATA_URL}?v=${Date.now()}`;
  const res = await fetch(bustUrl, { cache: 'no-store' });
  const text = await res.text();
  const xml = new DOMParser().parseFromString(text, 'application/xml');

  const parseErr = xml.querySelector('parsererror');
  if (parseErr) {
    console.error('Failed to parse deals.xml', parseErr.textContent);
    return [];
  }

  lastGeneratedIso = xml.documentElement.getAttribute('generated');
  updateLastUpdatedLabel();

  return Array.from(xml.querySelectorAll('deal')).map(el => {
    const get = tag => (el.querySelector(tag)?.textContent || '').trim();
    const rating = parseInt(get('rating'), 10);
    return {
      title: get('title'),
      link: get('link'),
      thumbnail: get('thumbnail'),
      description: get('description'),
      rating: Number.isFinite(rating) ? rating : 0,
      pubDateIso: get('pubDateIso'),
      expired: get('expired').toLowerCase() === 'true',
    };
  }).filter(d => d.link && d.pubDateIso);
}

function heatClass(rating) {
  if (rating >= 50) return 'hot';
  if (rating >= 20) return 'warm';
  return 'cool';
}

function heatColor(rating) {
  if (rating >= 50) return 'var(--hot)';
  if (rating >= 20) return 'var(--warm)';
  return 'var(--cool)';
}

function relativeTime(iso) {
  const then = new Date(iso).getTime();
  const diffMin = Math.max(0, Math.round((Date.now() - then) / 60000));
  if (diffMin < 1) return 'just now';
  if (diffMin < 60) return `${diffMin}m ago`;
  const diffHr = Math.floor(diffMin / 60);
  if (diffHr < 24) return `${diffHr}h ${diffMin % 60}m ago`;
  const diffDay = Math.floor(diffHr / 24);
  return `${diffDay}d ${diffHr % 24}h ago`;
}

function updateLastUpdatedLabel() {
  const el = document.getElementById('lastUpdated');
  if (!lastGeneratedIso) {
    el.textContent = 'Last updated: unknown';
    return;
  }
  el.textContent = `Last updated: ${relativeTime(lastGeneratedIso)}`;
}

function cardHtml(d, opts = {}) {
  const pct = Math.min(100, Math.max(6, (d.rating / 250) * 100));
  const hClass = heatClass(d.rating);
  const hColor = heatColor(d.rating);
  const isFav = favorites.has(d.link);
  // NOTE: onerror replaces only the  itself (this.outerHTML), never
  // this.parentElement -- replacing the parent would also wipe out the
  // sibling .rating-pill sitting next to the image.
  const thumbHtml = d.thumbnail
    ? `<img src="${d.thumbnail}" alt="" loading="lazy" onload="this.parentElement.style.aspectRatio=this.naturalWidth+'/'+this.naturalHeight" onerror="this.outerHTML='
No Image'">`
    : `
No Image`;

  return `



        ${thumbHtml}


          ★

        ${d.expired ? '
Expired' : ''}

▲ ${d.rating}








          ${d.rating} thumbs


${d.title}


          ${relativeTime(d.pubDateIso)}${opts.archived ? ' · saved' : ''}
          View deal ↗




  `;
}

function domainOf(url) {
  try {
    return new URL(url).hostname.replace(/^www\./, '');
  } catch {
    return url;
  }
}

function rowHtml(d, opts = {}) {
  const isFav = favorites.has(d.link);
  const thumbHtml = d.thumbnail
    ? `<img src="${d.thumbnail}" alt="" loading="lazy" onerror="this.parentElement.innerHTML='
No Img'">`
    : `
No Img`;

  return `


${thumbHtml}
      ▲ ${d.rating}
      ${d.title}
      ${d.description ? d.description : '—'}
      ${domainOf(d.link)}
      ${relativeTime(d.pubDateIso)}${opts.archived ? ' · saved' : ''}
      ${d.expired ? 'Expired' : 'Live'}


        ★


  `;
}

function rowsHeaderHtml() {
  return `



      Rating
      Title
      Description
      URL
      Pub Date
      Expired

  `;
}

function rowsTableHtml(deals, opts = {}) {
  return `




        ${rowsHeaderHtml()}
        ${deals.map(d => rowHtml(d, opts)).join('')}


  `;
}

function favRowsSectionHtml(favEntries) {
  return `




        ★ Favorites(${favEntries.length})
        Clear





          ${rowsHeaderHtml()}
          ${favEntries.map(f => rowHtml(f.deal, { archived: f.archived })).join('')}



  `;
}

function favBoxHtml(favEntries) {
  // Box grows one column-track wider per favorite (capped at 3) so a single
  // favorite doesn't reserve a big empty area -- extra favorites beyond that
  // just wrap onto additional rows inside the box, left to right.
  const span = Math.min(favEntries.length, 3);

  return `




        ★ Favorites(${favEntries.length})
        Clear



        ${favEntries.map(f => cardHtml(f.deal, { archived: f.archived })).join('')}


  `;
}

function render() {
  const cutoff = Date.now() - activeHours * 60 * 60 * 1000;
  let visible = allDeals.filter(d => new Date(d.pubDateIso).getTime() >= cutoff);

  visible.sort((a, b) => {
    if (activeSort === 'rating') return b.rating - a.rating;
    return new Date(b.pubDateIso) - new Date(a.pubDateIso);
  });

  const grid = document.getElementById('grid');
  const count = document.getElementById('count');
  count.textContent = `${visible.length} deal${visible.length === 1 ? '' : 's'} in the last ${activeHours}h`;

  const favEntries = getFavoriteDeals();

  grid.classList.toggle('rows-mode', activeLayout === 'rows');

  if (activeLayout === 'rows') {
    grid.classList.remove('grid');
    const favSection = favEntries.length > 0 ? favRowsSectionHtml(favEntries) : '';
    if (visible.length === 0) {
      grid.innerHTML = favSection + `
No deals in this window yet. The feed updates every 15 minutes.`;
      return;
    }
    grid.innerHTML = favSection + rowsTableHtml(visible);
    return;
  }

  grid.classList.add('grid');
  const favBox = favEntries.length > 0 ? favBoxHtml(favEntries) : '';

  if (visible.length === 0) {
    grid.innerHTML = favBox + `
No deals in this window yet. The feed updates every 15 minutes.`;
    return;
  }

  grid.innerHTML = favBox + visible.map(cardHtml).join('');
}

function setupControls() {
  document.querySelectorAll('.tab-btn').forEach(btn => {
    if (parseInt(btn.dataset.hours, 10) === activeHours) btn.classList.add('active');
    btn.addEventListener('click', () => {
      activeHours = parseInt(btn.dataset.hours, 10);
      document.querySelectorAll('.tab-btn').forEach(b => b.classList.toggle('active', b === btn));
      render();
    });
  });

  document.querySelectorAll('.layout-btn').forEach(btn => {
    if (btn.dataset.layout === activeLayout) btn.classList.add('active');
    btn.addEventListener('click', () => {
      activeLayout = btn.dataset.layout;
      document.querySelectorAll('.layout-btn').forEach(b => b.classList.toggle('active', b === btn));
      render();
    });
  });

  document.querySelectorAll('.sort-btn').forEach(btn => {
    if (btn.dataset.sort === activeSort) btn.classList.add('active');
    btn.addEventListener('click', () => {
      activeSort = btn.dataset.sort;
      document.querySelectorAll('.sort-btn').forEach(b => b.classList.toggle('active', b === btn));
      render();
    });
  });

  const refreshBtn = document.getElementById('refreshBtn');
  refreshBtn.addEventListener('click', async () => {
    refreshBtn.disabled = true;
    refreshBtn.textContent = 'Refreshing…';
    allDeals = await loadDeals();
    render();
    refreshBtn.disabled = false;
    refreshBtn.textContent = 'Refresh';
  });
}

(async function init() {
  setupControls();
  allDeals = await loadDeals();
  render();

  // Pick up new commits from the workflow without a manual reload.
  setInterval(async () => {
    allDeals = await loadDeals();
    render();
  }, 5 * 60 * 1000);

  // Keep the "Last updated: Xm ago" label ticking even between fetches.
  setInterval(updateLastUpdatedLabel, 30 * 1000);
})();
